mapper.select:
WITH time_series AS ( SELECT generate_series( date_trunc('hour', COALESCE(#{start}::timestamptz, NOW() - INTERVAL '24 hours')), date_trunc('hour', COALESCE(#{end}::timestamptz, NOW())), '1 hour'::interval ) AS time_bucket ), hourly_data AS ( SELECT date_trunc('hour', collected_at) AS time_bucket, COUNT(DISTINCT table_name) FILTER ( WHERE session_phase IS NOT NULL AND session_phase != 'not_running' ) AS avg_blockers FROM vacuum_raw_metrics WHERE collected_at BETWEEN COALESCE(#{start}, NOW() - INTERVAL '24 hours') AND COALESCE(#{end}, NOW())
AND database_id = #{databaseId}
GROUP BY date_trunc('hour', collected_at) ) SELECT TO_CHAR(ts.time_bucket, 'HH24:MI') AS hourLabel, COALESCE(hd.avg_blockers, 0) AS blockersCount FROM time_series ts LEFT JOIN hourly_data hd ON ts.time_bucket = hd.time_bucket ORDER BY ts.time_bucket

WITH latest_metrics AS ( SELECT DISTINCT ON (table_name) database_id, table_name, COALESCE(bloat_bytes, 0) AS bloat_bytes, COALESCE(bloat_ratio, 0) AS bloat_ratio, n_dead_tup AS dead_tuple_total, relsize_total_bytes AS table_size, collected_at FROM vacuum_raw_metrics WHERE collected_at BETWEEN COALESCE(#{start}, NOW() - INTERVAL '24 hours') AND COALESCE(#{end}, NOW()) AND table_name IS NOT NULL AND n_dead_tup > 0
AND database_id = #{databaseId}
ORDER BY table_name, collected_at DESC ) SELECT database_id AS databaseId, table_name AS tableName, bloat_bytes AS bloatBytes, bloat_ratio AS bloatRatio, dead_tuple_total AS deadTuples FROM latest_metrics WHERE bloat_ratio > 0 ORDER BY bloat_ratio DESC, bloat_bytes DESC LIMIT #{limit}

WITH recent_blockers AS ( SELECT DISTINCT ON (table_name) database_id, table_name, blocker_pid, blocked_seconds, transaction_age, blocker_lock_mode, query_state, is_blocked, session_phase, collected_at FROM vacuum_raw_metrics WHERE collected_at BETWEEN COALESCE(#{start}, NOW() - INTERVAL '24 hours') AND COALESCE(#{end}, NOW()) AND table_name IS NOT NULL AND ( -- ý░ĘŰőĘŰÉť vacuum (blocker_pidŕ░Ç ý×łŕ▒░Űéś is_blockedŕ░Ç true) (blocker_pid IS NOT NULL OR is_blocked = true) -- ŰśÉŰŐö ýőĄÝľë ýĄĹýŁŞ vacuum ýäŞýůś OR (session_phase IS NOT NULL AND session_phase != 'not_running') )
AND database_id = #{databaseId}
ORDER BY table_name, collected_at DESC ) SELECT database_id AS databaseId, table_name AS tableName, COALESCE(blocker_pid, (10000 + (database_id * 100 + ROW_NUMBER() OVER ())::INTEGER)) AS pid, COALESCE(blocker_lock_mode, CASE WHEN session_phase IN ('vacuuming', 'index_cleanup') THEN 'AccessExclusiveLock' WHEN session_phase IN ('scanning') THEN 'ShareUpdateExclusiveLock' ELSE 'ShareLock' END ) AS lockType, COALESCE(transaction_age, 0) AS transactionAge, COALESCE(blocked_seconds, 0) AS blockDuration, COALESCE(query_state, CASE WHEN session_phase IN ('vacuuming', 'index_cleanup') THEN 'idle in transaction' ELSE 'active' END ) AS queryState FROM recent_blockers WHERE (blocker_pid IS NOT NULL OR is_blocked = true OR (session_phase IS NOT NULL AND session_phase != 'not_running')) ORDER BY CASE WHEN blocker_pid IS NOT NULL OR is_blocked = true THEN 1 ELSE 2 END, COALESCE(blocked_seconds, 0) DESC, COALESCE(transaction_age, 0) DESC LIMIT 10

WITH latest_wraparound AS ( SELECT DISTINCT ON (database_id) database_id, -- Ôťů ýőĄýáť wraparound_progress ý╗ČŰč╝ ýéČýÜę (CollectorýŚÉýäť ŕ│äýé░ŰÉĘ) COALESCE( AVG(wraparound_progress) OVER (PARTITION BY database_id), -- Fallback: Dead Tuples ŕŞ░Ű░ś ŕĚ╝ýéČ ŕ│äýé░ LEAST( (SUM(n_dead_tup) OVER (PARTITION BY database_id)::NUMERIC / 200000000) * 100, 100 ) ) AS wraparound_progress_pct, collected_at FROM vacuum_raw_metrics WHERE collected_at BETWEEN COALESCE(#{start}, NOW() - INTERVAL '24 hours') AND COALESCE(#{end}, NOW())
AND database_id = #{databaseId}
ORDER BY database_id, collected_at DESC ) SELECT database_id AS databaseId, wraparound_progress_pct AS wraparoundProgressPct FROM latest_wraparound WHERE wraparound_progress_pct > 0 ORDER BY wraparound_progress_pct DESC, database_id LIMIT 5
